diff --git a/packages/netlify-cms-core/src/components/MediaLibrary/__tests__/MediaLibraryCard.spec.js b/packages/netlify-cms-core/src/components/MediaLibrary/__tests__/MediaLibraryCard.spec.js
new file mode 100644
index 0000000..cd2f640
--- /dev/null
+++ b/packages/netlify-cms-core/src/components/MediaLibrary/__tests__/MediaLibraryCard.spec.js
@@ -0,0 +1,47 @@
+import React from 'react';
+import { Map } from 'immutable';
+import MediaLibraryCard from '../MediaLibraryCard';
+import { render } from '@testing-library/react';
+
+describe('MediaLibraryCard', () => {
+  const props = {
+    displayURL: Map({ url: 'url' }),
+    text: 'image.png',
+    onClick: jest.fn(),
+    draftText: 'Draft',
+    width: '100px',
+    margin: '10px',
+    isViewableImage: true,
+    loadDisplayURL: jest.fn(),
+  };
+
+  it('should match snapshot for non draft image', () => {
+    const { asFragment, queryByTestId } = render(<MediaLibraryCard {...props} />);
+
+    expect(queryByTestId('draft-text')).toBeNull();
+    expect(asFragment()).toMatchSnapshot();
+  });
+
+  it('should match snapshot for draft image', () => {
+    const { asFragment, getByTestId } = render(<MediaLibraryCard {...props} isDraft={true} />);
+    expect(getByTestId('draft-text')).toHaveTextContent('Draft');
+    expect(asFragment()).toMatchSnapshot();
+  });
+
+  it('should match snapshot for non viewable image', () => {
+    const { asFragment, getByTestId } = render(
+      <MediaLibraryCard {...props} isViewableImage={false} type="Not Viewable" />,
+    );
+    expect(getByTestId('card-file-icon')).toHaveTextContent('Not Viewable');
+    expect(asFragment()).toMatchSnapshot();
+  });
+
+  it('should call loadDisplayURL on mount when url is empty', () => {
+    const loadDisplayURL = jest.fn();
+    render(
+      <MediaLibraryCard {...props} loadDisplayURL={loadDisplayURL} displayURL={Map({ url: '' })} />,
+    );
+
+    expect(loadDisplayURL).toHaveBeenCalledTimes(1);
+  });
+});

diff --git a/packages/netlify-cms-core/src/components/Editor/EditorControlPane/__tests__/PathPreview.spec.js b/packages/netlify-cms-core/src/components/Editor/EditorControlPane/__tests__/PathPreview.spec.js
new file mode 100644
index 0000000..836fba3
--- /dev/null
+++ b/packages/netlify-cms-core/src/components/Editor/EditorControlPane/__tests__/PathPreview.spec.js
@@ -0,0 +1,84 @@
+import React from 'react';
+import { Map } from 'immutable';
+import { createStore } from 'redux';
+import { Provider } from 'react-redux';
+import { render } from '@testing-library/react';
+import ConnectedPathPreview, { PathPreview } from '../PathPreview';
+
+jest.mock('Reducers', () => {
+  return () => ({});
+});
+jest.mock('Selectors/entryDraft');
+jest.mock('react-polyglot', () => {
+  return {
+    translate: () => Component => props => <Component {...props} t={jest.fn(key => key)} />,
+  };
+});
+
+describe('PathPreview', () => {
+  it('should render successfully and match snapshot', () => {
+    const props = {
+      value: 'posts/2019/index.md',
+      t: jest.fn(key => key),
+    };
+    const { asFragment } = render(<PathPreview {...props} />);
+
+    expect(asFragment()).toMatchSnapshot();
+  });
+});
+
+function renderWithRedux(ui, { initialState, store = createStore(() => ({}), initialState) } = {}) {
+  return {
+    ...render(<Provider store={store}>{ui}</Provider>),
+    store,
+  };
+}
+
+describe('ConnectedPathPreview', () => {
+  const { selectDraftPath } = require('Selectors/entryDraft');
+
+  beforeEach(() => {
+    jest.clearAllMocks();
+  });
+
+  it('should use existing path when newRecord is false', () => {
+    const props = {
+      collection: Map({
+        name: 'posts',
+      }),
+      entry: Map({
+        newRecord: false,
+        data: {},
+        path: 'existing-path/index.md',
+      }),
+    };
+    const { asFragment, getByTestId } = renderWithRedux(<ConnectedPathPreview {...props} />);
+
+    expect(selectDraftPath).toHaveBeenCalledTimes(0);
+
+    expect(getByTestId('site_path-preview')).toHaveValue('existing-path/index.md');
+
+    expect(asFragment()).toMatchSnapshot();
+  });
+
+  it('should evaluate preview path when newRecord is true', () => {
+    selectDraftPath.mockReturnValue('preview-path/index.md');
+    const props = {
+      collection: Map({
+        name: 'posts',
+      }),
+      entry: Map({
+        newRecord: true,
+        data: {},
+      }),
+    };
+    const { asFragment, getByTestId } = renderWithRedux(<ConnectedPathPreview {...props} />);
+
+    expect(selectDraftPath).toHaveBeenCalledTimes(1);
+    expect(selectDraftPath).toHaveBeenCalledWith({}, props.collection, props.entry);
+
+    expect(getByTestId('site_path-preview')).toHaveValue('preview-path/index.md');
+
+    expect(asFragment()).toMatchSnapshot();
+  });
+});

